.container {
  display: flex;
}

/* Inline flex — container stays inline */
.tag-list {
  display: inline-flex;
  gap: 8px;
}

/* Default — left to right */
.row { flex-direction: row; }

/* Top to bottom */
.stack { flex-direction: column; }

/* Reverse order */
.reversed { flex-direction: row-reverse; }

/* Common pattern: centered hero */
.hero {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Center horizontally */
.center { justify-content: center; }

/* Space between items, flush to edges */
.nav { justify-content: space-between; }

/* Equal space everywhere */
.pills { justify-content: space-evenly; }

/* Push to end */
.toolbar { justify-content: flex-end; }

/* Vertically center all items */
.card {
  display: flex;
  align-items: center;
  height: 100px;
}

/* Perfect centering (horizontal + vertical) */
.hero {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
}

/* Align text baselines */
.toolbar {
  display: flex;
  align-items: baseline;
}

/* Item fills remaining space */
.main-content {
  flex-grow: 1;
}

/* Sidebar stays fixed, content fills rest */
.layout {
  display: flex;
}
.sidebar { width: 250px; }
.content { flex-grow: 1; }

/* Proportional growing */
.col-2 { flex-grow: 2; } /* twice as wide as col-1 */
.col-1 { flex-grow: 1; }

/* flex: 1 — equal width columns */
.col { flex: 1; }

/* flex: 0 0 250px — fixed width, no grow/shrink */
.sidebar { flex: 0 0 250px; }

/* flex: 1 1 auto — grow and shrink from natural size */
.tag { flex: 1 1 auto; }

/* Common layout: fixed sidebar + fluid content */
.layout { display: flex; }
.sidebar { flex: 0 0 240px; }
.main    { flex: 1; }
